import{c as e,a7 as o,y as a,B as l}from"./chunks/framework.3cjvm90C.js";const f=JSON.parse('{"title":"ActorRolloutRefWorker","description":"解析veRL中Actor、Rollout与Reference模型联合Worker的实现","frontmatter":{"title":"ActorRolloutRefWorker","description":"解析veRL中Actor、Rollout与Reference模型联合Worker的实现"},"headers":[],"relativePath":"rlhf/infra/verl/fsdp_actor_worker.md","filePath":"rlhf/infra/verl/fsdp_actor_worker.md","lastUpdated":1782448598000}'),i={name:"rlhf/infra/verl/fsdp_actor_worker.md"};function s(t,r,n,d,p,c){return o(),a("div",null,[...r[0]||(r[0]=[l('<h1 id="actorrolloutrefworker" tabindex="-1">ActorRolloutRefWorker <a class="header-anchor" href="#actorrolloutrefworker" aria-label="Permalink to “ActorRolloutRefWorker”">​</a></h1><h2 id="整体概述" tabindex="-1">整体概述 <a class="header-anchor" href="#整体概述" aria-label="Permalink to “整体概述”">​</a></h2><p><code>ActorRolloutRefWorker</code> 是一个多功能的 Worker 类，可以根据配置扮演不同角色：单独的演员（actor）、推理引擎（rollout）、参考策略（ref），或者它们的组合（如 actor_rollout、actor_rollout_ref）。 fsdp_workers.py:106-110 这种设计实现了最大化的代码复用，同时支持高效的权重传输和内存管理。</p><h2 id="类初始化和配置" tabindex="-1">类初始化和配置 <a class="header-anchor" href="#类初始化和配置" aria-label="Permalink to “类初始化和配置”">​</a></h2><h3 id="构造函数参数解析-fsdp-workers-py-112-128" tabindex="-1">构造函数参数解析 fsdp_workers.py:112-128 <a class="header-anchor" href="#构造函数参数解析-fsdp-workers-py-112-128" aria-label="Permalink to “构造函数参数解析 fsdp_workers.py:112-128”">​</a></h3><p>构造函数接收配置对象和角色参数，首先初始化分布式环境。如果 PyTorch 分布式未初始化，会自动设置进程组，使用混合后端（CPU 用 gloo， GPU 用 NCCL）。</p><h3 id="设备网格构建-fsdp-workers-py-129-143" tabindex="-1">设备网格构建 fsdp_workers.py:129-143 <a class="header-anchor" href="#设备网格构建-fsdp-workers-py-129-143" aria-label="Permalink to “设备网格构建 fsdp_workers.py:129-143”">​</a></h3><p>代码构建了两种设备网格：</p><ul><li><strong>FSDP 设备网格</strong>：用于参数分片的基础网格</li><li><strong>Ulysses 设备网格</strong>：用于序列并行的专用网格，支持长序列处理</li></ul><h3 id="角色判断逻辑-fsdp-workers-py-147-153" tabindex="-1">角色判断逻辑 fsdp_workers.py:147-153 <a class="header-anchor" href="#角色判断逻辑-fsdp-workers-py-147-153" aria-label="Permalink to “角色判断逻辑 fsdp_workers.py:147-153”">​</a></h3><p>通过布尔标志确定当前实例需要承担的角色：</p><ul><li><code>_is_actor</code>：是否需要执行策略更新</li><li><code>_is_rollout</code>：是否需要执行序列生成</li><li><code>_is_ref</code>：是否需要作为参考策略</li></ul><h3 id="配置标准化-fsdp-workers-py-174-208" tabindex="-1">配置标准化 fsdp_workers.py:174-208 <a class="header-anchor" href="#配置标准化-fsdp-workers-py-174-208" aria-label="Permalink to “配置标准化 fsdp_workers.py:174-208”">​</a></h3><p>这段代码对批次大小进行标准化处理，根据设备数量和序列并行大小调整：</p><ul><li><strong>PPO mini batch size</strong>：按设备数量缩放</li><li><strong>Micro batch size</strong>：确保能被 mini batch size 整除</li><li><strong>日志概率批次大小</strong>：为推理和 Reference 单独配置</li></ul><h2 id="模型构建核心方法" tabindex="-1">模型构建核心方法 <a class="header-anchor" href="#模型构建核心方法" aria-label="Permalink to “模型构建核心方法”">​</a></h2><h3 id="build-model-optimizer-方法-fsdp-workers-py-254-330" tabindex="-1">_build_model_optimizer 方法 fsdp_workers.py:254-330 <a class="header-anchor" href="#build-model-optimizer-方法-fsdp-workers-py-254-330" aria-label="Permalink to “_build_model_optimizer 方法 fsdp_workers.py:254-330”">​</a></h3><p>这是模型构建的核心方法：</p><ol><li><p><strong>模型配置加载</strong>：从预训练路径加载 AutoConfig，设置 flash attention</p></li><li><p><strong>特殊模型适配</strong>：为 kimi-vl 等特殊模型设置专用配置</p></li><li><p><strong>权重初始化上下文</strong>：使用 meta tensor 优化内存使用</p></li><li><p><strong>模型类型判断</strong>：自动选择 AutoModelForCausalLM 或 AutoModelForVision2Seq</p></li><li><p>优化内核应用</p><p>：</p><ul><li>Liger 内核优化（如果启用）</li><li>Monkey patch 应用（支持 remove padding 和序列并行）</li><li>梯度检查点（如果启用）</li></ul></li><li><p><strong>LoRA 支持</strong>：如果配置了 LoRA，会应用 PEFT 模型包装</p></li></ol><h2 id="模型初始化流程" tabindex="-1">模型初始化流程 <a class="header-anchor" href="#模型初始化流程" aria-label="Permalink to “模型初始化流程”">​</a></h2><h3 id="init-model-方法-fsdp-workers-py-563-668" tabindex="-1">init_model 方法 fsdp_workers.py:563-668 <a class="header-anchor" href="#init-model-方法-fsdp-workers-py-563-668" aria-label="Permalink to “init_model 方法 fsdp_workers.py:563-668”">​</a></h3><p>这个方法是模型初始化的入口点，使用 <code>@register(dispatch_mode=Dispatch.ONE_TO_ALL)</code> 装饰器，确保所有 Worker 都执行相同的初始化：</p><ol><li><strong>外部库导入</strong>：导入用户指定的外部库</li><li><strong>演员/推理模型构建</strong>：如果角色包含 actor 或 rollout，构建主模型</li><li><strong>演员包装</strong>：将 FSDP 模型包装为 <code>DataParallelPPOActor</code></li><li><strong>推理引擎构建</strong>：构建 vLLM 推理引擎和分片管理器</li><li><strong>Reference 构建</strong>：如果需要参考策略，构建独立的 Reference</li><li><strong>检查点管理器</strong>：设置 FSDP 检查点管理器</li></ol><h2 id="核心训练方法" tabindex="-1">核心训练方法 <a class="header-anchor" href="#核心训练方法" aria-label="Permalink to “核心训练方法”">​</a></h2><h3 id="update-actor-方法-fsdp-workers-py-669-713" tabindex="-1">update_actor 方法 fsdp_workers.py:669-713 <a class="header-anchor" href="#update-actor-方法-fsdp-workers-py-669-713" aria-label="Permalink to “update_actor 方法 fsdp_workers.py:669-713”">​</a></h3><p>这是演员模型更新的核心方法：</p><ol><li><p><strong>数据预处理</strong>：将数据移动到 GPU，处理 CPU 卸载</p></li><li><p><strong>Ulysses 分片管理</strong>：使用上下文管理器处理序列并行</p></li><li><p><strong>策略更新</strong>：调用 <code>DataParallelPPOActor.update_policy</code> 执行 PPO 更新</p></li><li><p>性能指标计算</p><p>：</p><ul><li>计算 MFU （模型 FLOPS 利用率）</li><li>记录内存使用情况</li><li>更新学习率调度器</li></ul></li><li><p><strong>数据后处理</strong>：处理输出数据并移回 CPU</p></li></ol><h2 id="检查点管理" tabindex="-1">检查点管理 <a class="header-anchor" href="#检查点管理" aria-label="Permalink to “检查点管理”">​</a></h2><h3 id="load-checkpoint-方法-fsdp-workers-py-884-903" tabindex="-1">load_checkpoint 方法 fsdp_workers.py:884-903 <a class="header-anchor" href="#load-checkpoint-方法-fsdp-workers-py-884-903" aria-label="Permalink to “load_checkpoint 方法 fsdp_workers.py:884-903”">​</a></h3><p>支持从本地或 HDFS 加载检查点，处理参数和优化器的 CPU 卸载逻辑。</p><h2 id="异步扩展" tabindex="-1">异步扩展 <a class="header-anchor" href="#异步扩展" aria-label="Permalink to “异步扩展”">​</a></h2><h3 id="asyncactorrolloutrefworker-类-fsdp-workers-py-1644-1700" tabindex="-1">AsyncActorRolloutRefWorker 类 fsdp_workers.py:1644-1700 <a class="header-anchor" href="#asyncactorrolloutrefworker-类-fsdp-workers-py-1644-1700" aria-label="Permalink to “AsyncActorRolloutRefWorker 类 fsdp_workers.py:1644-1700”">​</a></h3><p>这是 <code>ActorRolloutRefWorker</code> 的异步版本，专门用于与 vLLM 和 SGLang 等异步推理引擎集成：</p><ul><li><strong>异步方法支持</strong>：提供 <code>async def</code> 方法用于非阻塞推理</li><li><strong>外部引擎集成</strong>：支持 vLLM 的 collective RPC 和 SGLang 的聊天完成接口</li><li><strong>资源管理</strong>：支持推理引擎的睡眠/唤醒机制</li></ul><h2 id="技术要点" tabindex="-1">技术要点 <a class="header-anchor" href="#技术要点" aria-label="Permalink to “技术要点”">​</a></h2><h3 id="_1-hybridflow-架构集成" tabindex="-1">1. HybridFlow 架构集成 <a class="header-anchor" href="#_1-hybridflow-架构集成" aria-label="Permalink to “1. HybridFlow 架构集成”">​</a></h3><p>所有方法都使用 <code>@register</code> 装饰器，支持不同的分发模式：</p><ul><li><code>Dispatch.ONE_TO_ALL</code>：广播到所有 Worker</li><li><code>Dispatch.DP_COMPUTE_PROTO</code>：数据并行计算和收集</li></ul><h3 id="_2-内存优化策略" tabindex="-1">2. 内存优化策略 <a class="header-anchor" href="#_2-内存优化策略" aria-label="Permalink to “2. 内存优化策略”">​</a></h3><ul><li><strong>参数卸载</strong>：支持将 FSDP 参数卸载到 CPU</li><li><strong>优化器卸载</strong>：支持将优化器状态卸载到 CPU</li><li><strong>激活检查点</strong>：减少前向传播的内存占用</li></ul><h3 id="_3-分布式训练支持" tabindex="-1">3. 分布式训练支持 <a class="header-anchor" href="#_3-分布式训练支持" aria-label="Permalink to “3. 分布式训练支持”">​</a></h3><ul><li><strong>FSDP 集成</strong>：使用 PyTorch FSDP 进行参数分片</li><li><strong>序列并行</strong>：通过 Ulysses 支持长序列处理</li><li><strong>混合精度</strong>：演员模型使用 fp32， Reference 使用 bfloat16</li></ul><h2 id="潜在改进建议" tabindex="-1">潜在改进建议 <a class="header-anchor" href="#潜在改进建议" aria-label="Permalink to “潜在改进建议”">​</a></h2><ol><li><strong>错误处理增强</strong>：可以添加更详细的异常处理和恢复机制</li><li><strong>配置验证</strong>：在初始化时验证配置参数的一致性和合理性</li><li><strong>内存监控</strong>：添加更精细的内存使用监控和报告</li><li><strong>性能优化</strong>：考虑使用更高效的数据传输和同步策略</li></ol><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to “Notes”">​</a></h2><p><code>ActorRolloutRefWorker</code> 是 verl 框架 FSDP 后端的核心实现，与 Megatron 后端形成互补。它通过角色组合设计实现了灵活的资源配置，支持从单机训练到大规模分布式训练的各种场景。该类在 HybridFlow 架构中作为计算流的具体执行者，通过 Ray 远程调用与控制流进行交互。</p>',46)])])}const k=e(i,[["render",s]]);export{f as __pageData,k as default};
